    // Add only if header doesn't exist.
    ADD_IF_ABSENT = 1;

    // Overwrite existing values or add if absent.
    OVERWRITE_IF_EXISTS_OR_ADD = 2;

    // Overwrite only if header exists, no-op if absent.
    OVERWRITE_IF_EXISTS = 3;
  }

